// Instruction Strategist v6 — Keywords + Structure + EEAT + Style + Brief Enforcement
const input = $('Webhook1').first().json.body;

function parseKeywords(raw) {
  if (!raw) return [];
  // Accept both array format ["kw1", "kw2"] and string format "kw1, kw2"
  if (Array.isArray(raw)) {
    return raw.flatMap(item => item.split(',').map(k => k.trim())).filter(k => k.length > 0);
  }
  if (typeof raw !== 'string') return [];
  return raw.split(',').map(k => k.trim()).filter(k => k.length > 0);
}

// Normalize: primary_keywords can arrive as array ["kw"] or string "kw"
const rawPrimary = input.primary_keywords;
const primary = (Array.isArray(rawPrimary) 
  ? rawPrimary.join(', ') 
  : (rawPrimary || '')
).trim();
const secondaryList = parseKeywords(input.secondary_keywords);       
const semanticList = parseKeywords(input.semantic_theme);
let wordCount = parseInt(input.word_count) || 1500; // will be overridden by brief below
const creativeBrief = (input.creative_brief || '').trim();
const clientName = (input.client_name || 'the client').trim();

// SMART WORD COUNT — Brief takes priority over form value
// Now that creativeBrief is defined, detect the real word count target
if (creativeBrief) {
  const globalWcPatterns = [
    /target\s+word\s+count[:\s~]*([\d,]+)/i,
    /word\s+count[:\s~]*([\d,]+)/i,
    /reading\s+time[^\n]*?([\d,]+)\s*words/i,
    /approximately\s+([\d,]+)\s*words/i,
    /~([\d,]+)\s*words?(?:\s+total|\s+for\s+the\s+(?:article|blog|post))?/i,
    /([\d,]+)[\s-]*word\s+(?:article|blog|post|target)/i,
  ];
  let briefGlobalWc = 0;
  for (const pattern of globalWcPatterns) {
    const match = creativeBrief.match(pattern);
    if (match) {
      const parsed = parseInt(match[1].replace(/,/g, ''));
      if (parsed >= 200 && parsed <= 10000) { briefGlobalWc = parsed; break; }
    }
  }
  if (briefGlobalWc > 0) {
    wordCount = briefGlobalWc;
  } else {
    const sectionWcPattern = /(?:~|\(|about\s*)(\d+)(?:\s*-\s*(\d+))?\s*words?/gi;
    let sectionTotal = 0, sectionCount = 0, sectionMatch;
    while ((sectionMatch = sectionWcPattern.exec(creativeBrief)) !== null) {
      const low = parseInt(sectionMatch[1]);
      const high = sectionMatch[2] ? parseInt(sectionMatch[2]) : low;
      const avg = Math.round((low + high) / 2);
      if (avg >= 50 && avg <= 500) { sectionTotal += avg; sectionCount++; }
    }
    if (sectionCount >= 2 && sectionTotal >= 300) { wordCount = sectionTotal; }
  }
}

// Calculate target frequency (Backlinko: ~8 per 3200 words, scaled)
const targetFreq = Math.max(3, Math.round((wordCount / 3200) * 8));

// Build secondary block
const allSecondary = [...secondaryList, ...semanticList]
  .filter((v, i, a) => a.indexOf(v) === i);

const secondaryBlock = allSecondary
  .map((kw, i) => '   ' + (i+1) + '. "' + kw + '" — use at least once, naturally woven into a sentence')
  .join('\n');

// ========== NEW: Parse Creative Brief for structural elements ==========

// Extract FAQ questions from brief — robust multi-strategy parsing
let briefFAQs = [];

// Strategy 1: Find the FAQ section header and grab everything after it
const faqHeaderPatterns = [
  /FAQ\s*Section[^\n]*/i,
  /FAQ[s]?\s*[:(]/i,
  /Frequently\s+Asked\s+Questions/i
];

let faqSectionStart = -1;
for (const pattern of faqHeaderPatterns) {
  const match = creativeBrief.match(pattern);
  if (match) {
    faqSectionStart = match.index + match[0].length;
    break;
  }
}

if (faqSectionStart > -1) {
  // Grab all lines after the FAQ header
  const afterFaq = creativeBrief.substring(faqSectionStart);
  const lines = afterFaq.split('\n')
    .map(line => line.trim())
    .filter(line => line.length > 0);

  // Extract lines that look like questions (end with ? or start with Q:/number)
  const questions = [];
  for (const line of lines) {
    // Stop if we hit another major section header
    if (/^(H[2-4]|##|Meta|Title|Tone|Brand|Audience|Internal|CTA|Conclusion|Key\s*Takeaway)/i.test(line)) break;

    const cleaned = line
      .replace(/^[-*•\d]+[.)\s]+/, '')  // Remove list markers
      .replace(/^Q[:\s]+/i, '')           // Remove Q: prefix
      .trim();

    if (cleaned.endsWith('?') && cleaned.length > 10) {
      questions.push(cleaned);
    }
  }

  if (questions.length > 0) briefFAQs = questions;
}

// Strategy 2: Fallback — find ALL question-mark lines in the brief
if (briefFAQs.length === 0) {
  const allQuestions = creativeBrief.split('\n')
    .map(line => line.trim())
    .filter(line => line.endsWith('?') && line.length > 15)
    .map(line => line.replace(/^[-*•\d]+[.)\s]+/, '').replace(/^Q[:\s]+/i, '').trim());

  if (allQuestions.length >= 2) {
    briefFAQs = allQuestions;
  }
}

// Extract H2/heading structure from brief
let briefHeadings = [];
const headingPatterns = [
  /H2[s]?[:\s]*\n([\s\S]*?)(?=\n\n|$)/i,
  /Headings?[:\s]*\n([\s\S]*?)(?=\n\n|$)/i,
  /Outline[:\s]*\n([\s\S]*?)(?=\n\n|$)/i,
  /Structure[:\s]*\n([\s\S]*?)(?=\n\n|$)/i,
  /Sections?[:\s]*\n([\s\S]*?)(?=\n\n|$)/i
];

for (const pattern of headingPatterns) {
  const match = creativeBrief.match(pattern);
  if (match) {
    const headingBlock = match[1];
    const headings = headingBlock.split('\n')
      .map(line => line.trim())
      .filter(line => line.length > 3)
      .map(line => line.replace(/^[-*•\d]+[.)\s]+/, '').replace(/^H[23]:\s*/i, '').trim())
      .filter(line => line.length > 3);
    if (headings.length > 0) briefHeadings = headings;
    break;
